import { cn } from "@/lib/utils";
import michelinStar from "@/assets/michelin-star.svg";

interface MichelinBadgeProps {
  stars: string | null | undefined;
  compact?: boolean;
  className?: string;
}

function getStarCount(stars: string): number {
  if (stars === "3") return 3;
  if (stars === "2") return 2;
  if (stars === "1") return 1;
  return 0;
}

export function MichelinBadge({ stars, compact = false, className }: MichelinBadgeProps) {
  if (!stars) return null;

  const count = getStarCount(stars);
  if (count === 0) return null;

  const size = compact ? 16 : 22;

  return (
    <div
      className={cn(
        "inline-flex items-center",
        compact ? "gap-0.5" : "gap-1",
        className,
      )}
    >
      {Array.from({ length: count }).map((_, i) => (
        <img key={i} src={michelinStar} alt="" width={size} height={size} className="drop-shadow-sm" />
      ))}
    </div>
  );
}

export function getMichelinStarsNumber(stars: string | null | undefined): number {
  if (stars === "3") return 3;
  if (stars === "2") return 2;
  if (stars === "1") return 1;
  return 0;
}
